import React from 'react';

function Education({ data }) {
  if (!data) return null;

  return (
    <section id="education" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            Formation
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19] leading-tight"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Education timeline
          </h2>
        </div>

        <div className="grid md:grid-cols-2 gap-4 md:gap-5">
          {data.map((edu) => (
            <article key={edu.id} className="rounded-3xl border border-[#ddd3c5] bg-white p-5 md:p-6 shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
              <div className="flex items-start gap-4">
              {(edu.image || edu.institution === 'Chandigarh University' || edu.institution === 'Kumarkhatri Govt. College, Kushia') ? (
                  <div className="flex-shrink-0 w-14 h-14 flex items-center justify-center bg-[#f4efe7] rounded-xl overflow-hidden border border-[#eee6da]">
                  <img
                    src={edu.image || (edu.institution === 'Chandigarh University' ? '/chandigarh-university.png' : '/images.png')}
                    alt={edu.institution}
                    className="w-full h-full object-contain p-1"
                  />
                </div>
              ) : edu.icon ? (
                  <div className="flex-shrink-0 w-14 h-14 flex items-center justify-center bg-[#f4efe7] rounded-xl text-2xl border border-[#eee6da]">
                  {edu.icon}
                </div>
              ) : null}
              
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] uppercase tracking-[0.28em] text-[#857d6f] mb-2">{edu.period}</p>
                  <h3 className="text-lg md:text-xl font-black text-[#1f1d1a] mb-1 leading-tight">
                  {edu.institution}
                </h3>
                  <p className="text-sm md:text-base text-[#5d564b] mb-2">
                  {edu.degree}
                </p>
                  {edu.details && <p className="text-sm text-[#746d61] leading-relaxed">{edu.details}</p>}
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Education;
